C++<pre><code>class Solution {
public:
    int search(vector&lt;int&gt;&amp; nums, int target) {
        int n = nums.size() - 1;
        if(nums[0] &gt; target || nums[n] &lt; target)
            return -1;
        int l = -1, r = n + 1;
        while(l + 1 != r)
        {
            int mid = (l + r) / 2;
            if(nums[mid] &lt;  target) l = mid;
            else r = mid;
        }
        if(nums[r] == target) return r;
        else return -1;
    }
};
</code></pre>

