C++<pre><code>class Solution {
public:
    int mySqrt(int x) {
        if(x == 0) return 0;
        if(x == 1) return 1;
        int l = -1, r = x;
        while (l + 1 != r)
        {
            long long mid = (l + r) / 2;
            if (mid * mid &lt;= x)
                l = mid;
            else
                r = mid;
        }
        return l;
    }
};
