C++<pre><code>class Sacles_data
{
public:
    Sacles_data() = default;
    Sacles_data(const string &amp;s) : bookNo(s) {}
    Sacles_data(const string &amp;s, unsigned n, double p) : bookNo(s), units_sold(n), revenue(p * n) {}
    Sacles_data(istream &amp;);
